    HRESULT hr = cwinrt_event_handler_create(fn, ctx, &handler);
    if (FAILED(hr)) return tok;
    hr = cwinrt_event_subscribe((IUnknown *)self, 12u, 13u, handler, &eh);
    handler->lpVtbl->Release(handler);
    if (FAILED(hr)) return tok;
